nlpql_libraries.sample_nlpql:
// Phenotype library name
phenotype "ifu_information" version "1";
include ClarityCore version "1.0" called Clarity;
termset ig_death_terms: ["death","expire","decease"];
define final ig_death_unstructured: Clarity.ProviderAssertion({termset: [ig_death_terms]});
define final ig_death:Tuple {"questionConcept": "5","answerValue": ig_death_unstructured.term,"answerType": "ProviderAssertion","sourceNote": ig_death_unstructured.sentence} where ig_death_unstructured;
